input.command:
python3 - <<'PY'
import os

# 1. Append log_format + limit_req_zone to nginx.conf http block if not present
conf = '/etc/nginx/nginx.conf'
with open(conf) as f:
    c = f.read()
if 'log_format benchmark' not in c:
    inject = (
        "\n\t##\n\t# Benchmark custom log format and rate limiting\n\t##\n"
        "\tlog_format benchmark '$time_local $request_method $status \"$http_user_agent\"';\n"
        "\tlimit_req_zone $binary_remote_addr zone=benchmark_limit:10m rate=10r/s;\n"
    )
    marker = "\taccess_log /var/log/nginx/access.log;"
    c = c.replace(marker, marker + inject, 1)
    with open(conf, 'w') as f:
        f.write(c)
    print("nginx.conf updated")
else:
    print("nginx.conf already has benchmark format")

# 2. server config
os.makedirs('/etc/nginx/conf.d', exist_ok=True)
site = """server {
    listen 8080;
    server_name localhost;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark;
    error_log /var/log/nginx/benchmark-error.log;

    limit_req zone=benchmark_limit burst=10 nodelay;

    location / {
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        internal;
    }
}
"""
with open('/etc/nginx/conf.d/benchmark-site.conf', 'w') as f:
    f.write(site)
print("benchmark-site.conf written")

# 3. document root
os.makedirs('/var/www/html', exist_ok=True)

# 4. index.html
with open('/var/www/html/index.html', 'w') as f:
    f.write("Welcome to the benchmark webserver\n")

# 5. 404.html
with open('/var/www/html/404.html', 'w') as f:
    f.write("Page not found - Please check your URL\n")
print("web files written")

# 6. disable default site
d = '/etc/nginx/sites-enabled/default'
if os.path.islink(d) or os.path.exists(d):
    os.remove(d)
    print("default site removed")
else:
    print("default site not present")
PY
